endpoint.response:
{ items:[ {
  id:number, name:string,
  referent_type: { id:number, name:string } | null,
  contact_scope: 'internal' | 'external',
  primary_contact: { type:string, value:string } | null,
  created_at:string,
  actions: string[]
} ], pagination:{ total, offset, limit, total_pages } }
Eager loading di referentType + personalData.contacts (no N+1); nessun campo sensibile.

endpoint.request:
{
  referent_type_id: number | null (optional; exists:referent_types,id),
  contact_scope: 'internal' | 'external' (required; default 'internal' lato form),
  notes: string | null (optional; max 5000),
  personal_data: { ...carta... , contacts?:[...], addresses?:[...] }  (REQUIRED su create — name derivato dalla carta)
}
